> @@ -3854,34 +3761,34 @@ static int __folio_freeze_and_split_unmapped(struct folio *folio, unsigned int n
>  	struct folio *end_folio = folio_next(folio);
>  	struct folio *new_folio, *next;
>  	int old_order = folio_order(folio);
> +	struct list_lru_one *l;
> +	bool dequeue_deferred;
>  	int ret = 0;
>  
>  	VM_WARN_ON_ONCE(!mapping && end);
>  	/* Prevent deferred_split_scan() touching ->_refcount */
> +	dequeue_deferred = folio_test_anon(folio) && old_order > 1;
> +	if (dequeue_deferred) {
> +		rcu_read_lock();
> +		l = list_lru_lock(&deferred_split_lru,
> +				  folio_nid(folio), folio_memcg(folio));
> +	}

Can this deadlock with interrupt handlers?

Other paths like __folio_unqueue_deferred_split() acquire this lock using
list_lru_lock_irqsave() because unqueueing can happen in hardirq or softirq
context when the last folio reference is dropped. 

If an interrupt fires while this list_lru_lock() is held and attempts to
unqueue a folio in the same memcg, will it cause a self-deadlock since
interrupts are not disabled here?

